    threadgroup_barrier(mem_flags::mem_threadgroup);

    // ---- Layer 2: 64 → 10, none ----
    if (tid < OUT2) {
        device const float* W2 = params + W2_OFF;
        device const float* B2 = params + B2_OFF;

        float sum = B2[tid];
        for (uint k = 0; k < OUT1; k++) {
            sum += act1[k] * W2[k * OUT2 + tid];
