}

/// Create a compute command encoder on the given command buffer.
pub fn beginCompute(
    self: *const Device,
    cmd_buf: objc.Object,
) objc.Object {
    // Assert the device has a valid command queue.
    std.debug.assert(self.command_queue.value != null);
    std.debug.assert(cmd_buf.value != null);

    return cmd_buf.msgSend(
        objc.Object,
        "computeCommandEncoder",
        .{},
    );
}

/// Dispatch a 1D compute kernel.
pub fn dispatch1D(
    self: *const Device,
    encoder: objc.Object,
    pipeline: ComputePipeline,
    count: u32,
) void {
    std.debug.assert(count > 0);
    // Assert the device is in a valid state.
    std.debug.assert(self.command_queue.value != null);

    encoder.msgSend(
        void,
        "setComputePipelineState:",
        .{pipeline.state.value},
    );

    // Use cached hardware limit to avoid Obj-C message
    // send overhead on every dispatch (Rule 7 — amortise).
    const threads_per_group = @min(
        pipeline.max_threads_per_group,
        @as(c_ulong, count),
    );
    std.debug.assert(threads_per_group > 0);

    // Switch to dispatchThreadgroups for better efficiency.
    // Round up thread count to full threadgroups.
    const thread_count = @as(c_ulong, count);
    const groups_needed = (thread_count + threads_per_group - 1) / threads_per_group;

pub fn sampleToken(
    logits: []f32,
    params: SamplingParams,
    scratch: []f32,
    indices: []u32,
    rng: std.Random,
) u32 {
    std.debug.assert(logits.len > 0);

    // Greedy: just return the argmax.
    if (params.temperature == 0.0) {
        return argmax(logits);
    }

    std.debug.assert(params.temperature > 0.0);

    // Temperature scaling.
    applyTemperature(logits, params.temperature);

    // Top-k filtering.
    if (params.top_k > 0) {
        applyTopK(logits, params.top_k, scratch);
    }

    // Top-p (nucleus) filtering.
    if (params.top_p < 1.0) {
        applyTopP(
            logits,
            params.top_p,
            scratch,
            indices,
        );
    }

    // Convert to probabilities and sample.
    softmaxInPlace(logits);
    return sampleFromDistribution(logits, rng);
}

/// Draw a token from a probability distribution using the
/// inverse-CDF method.  `probs` must sum to ~1.0.
fn sampleFromDistribution(
    probs: []const f32,
    rng: std.Random,
) u32 {
    std.debug.assert(probs.len > 0);

    const r: f32 = rng.float(f32);
    var cumulative: f32 = 0.0;
    for (probs, 0..) |p, i| {
        cumulative += p;
        if (cumulative > r) return @intCast(i);
    }
    // Rounding tail: return last token.
    return @intCast(probs.len - 1);
}

/// Read f32 logits from a raw Metal buffer handle.
/// The caller must ensure no GPU work is in flight on
/// this buffer (Rule 26: commitAndWait before reading).
fn readLogitsSlice(
    logits_obj: objc.Object,
    count: u32,
) []f32 {
    std.debug.assert(logits_obj.value != null);
    std.debug.assert(count > 0);

    const ptr = logits_obj.msgSend(
        *anyopaque,
        "contents",
        .{},
    );
    const float_ptr: [*]f32 = @ptrCast(
        @alignCast(ptr),
    );
    return float_ptr[0..@as(usize, count)];
}

